// =============================================================================
// Preparação Sazonal — BACKTEST v2 (chunked, sem Drive)
//
// Lê a planilha de Redis (cacheada em phase='start'), processa SOMENTE a fatia
// solicitada e devolve o array de análises por SKU/mes-alvo, no shape esperado
// pelo Python.
// =============================================================================

const src = $json.source;
if (!src) {
  throw new Error("backtest-source vazio. Chame phase='start' antes de phase='chunk'.");
}
const rowsAll = JSON.parse(src);
const body = $('Webhook').first().json.body || {};

const skuOffset = Math.max(0, parseInt(body.skuOffset, 10) || 0);
const skuLimitRaw = parseInt(body.skuLimit, 10);
const skuLimit = Number.isFinite(skuLimitRaw) && skuLimitRaw > 0 ? skuLimitRaw : 30;
let targetMonths = Array.isArray(body.targetMonths) ? body.targetMonths : [];

const totalSkus = rowsAll.length;
const skuItems = rowsAll.slice(skuOffset, skuOffset + skuLimit);

const WINDOW_OFFSET = 2;

// Default: últimos 3 meses presentes na planilha
if (targetMonths.length === 0) {
  const found = new Set();
  for (const sku of rowsAll) {
    for (const k of Object.keys(sku)) {
      if (/^\d{4}-\d{2}$/.test(k) && sku[k] != null && !isNaN(Number(sku[k]))) {
        found.add(k);
      }
    }
  }
  targetMonths = [...found].sort().slice(-3);
}

const results = [];

for (const targetMonth of targetMonths) {
  const m = targetMonth.match(/^(\d{4})-(\d{2})$/);
  if (!m) continue;
  const targetYear = parseInt(m[1], 10);
  const targetMonthNum = parseInt(m[2], 10);

  for (const sku of skuItems) {
    const skuCode = sku.SKU;
    const description = sku["Descrição"];
    const formato = sku.Formato;

    const salesByYearMonth = {};
    const allYears = new Set();
    let realValue = null;
    let monthsAvailable = 0;

    for (const key of Object.keys(sku)) {
      const km = key.match(/^(\d{4})-(\d{2})$/);
      if (!km) continue;
      const v = sku[key];
      if (v == null || v === "" || isNaN(Number(v))) continue;
      const y = parseInt(km[1], 10);
      const mm = parseInt(km[2], 10);
      const numericValue = Number(v);

      if (y === targetYear && mm === targetMonthNum) {
        realValue = numericValue;
        continue;
      }
      if (y < targetYear || (y === targetYear && mm < targetMonthNum)) {
        if (!salesByYearMonth[y]) salesByYearMonth[y] = {};
        salesByYearMonth[y][mm] = numericValue;
        allYears.add(y);
        monthsAvailable++;
      }
    }

    const sortedYears = [...allYears].sort((a, b) => a - b);

    const windowMonths = [];
    for (let off = -WINDOW_OFFSET; off <= WINDOW_OFFSET; off++) {
      let wm = targetMonthNum + off;
      if (wm < 1) wm += 12;
      if (wm > 12) wm -= 12;
      windowMonths.push(wm);
    }
    const historicalYears = sortedYears.filter((y) => y < targetYear);
    const historicalData = {};
    for (const year of historicalYears) {
      const yd = {};
      for (const wm of windowMonths) {
        if (salesByYearMonth[year] && salesByYearMonth[year][wm] !== undefined) {
          yd[`${year}-${String(wm).padStart(2, "0")}`] = salesByYearMonth[year][wm];
        }
      }
      if (Object.keys(yd).length) historicalData[year] = yd;
    }
    const targetMonthHistory = [];
    for (const year of historicalYears) {
      if (salesByYearMonth[year] && salesByYearMonth[year][targetMonthNum] !== undefined) {
        targetMonthHistory.push({ year, value: salesByYearMonth[year][targetMonthNum] });
      }
    }
    // historicalContext: para cada ano histórico do mês-alvo, monta
    // {year, actual, recent[3 meses anteriores], forecastStat (média de anos < year)}
    // Usado pela calibração por SKU (escolhe wRecent que minimiza erro neste SKU).
    const historicalContext = [];
    for (const entry of targetMonthHistory) {
      const yr = entry.year;
      const recent = [];
      let cy = yr, cm = targetMonthNum - 1;
      if (cm < 1) { cm = 12; cy--; }
      for (let i = 0; i < 3; i++) {
        if (salesByYearMonth[cy] && salesByYearMonth[cy][cm] !== undefined) {
          recent.push(salesByYearMonth[cy][cm]);
        }
        cm--; if (cm < 1) { cm = 12; cy--; }
      }
      const priorVals = targetMonthHistory.filter((e) => e.year < yr).map((e) => e.value);
      const forecastStat = priorVals.length
        ? priorVals.reduce((a, b) => a + b, 0) / priorVals.length
        : entry.value;
      if (recent.length) {
        historicalContext.push({
          year: yr,
          actual: entry.value,
          recent,
          forecastStat: parseFloat(forecastStat.toFixed(3)),
        });
      }
    }
    const recentMonths = [];
    let ry = targetYear, rm = targetMonthNum - 1;
    if (rm < 1) { rm = 12; ry--; }
    for (let i = 0; i < 6; i++) {
      if (salesByYearMonth[ry] && salesByYearMonth[ry][rm] !== undefined) {
        recentMonths.push({ key: `${ry}-${String(rm).padStart(2, "0")}`, value: salesByYearMonth[ry][rm] });
      }
      rm--; if (rm < 1) { rm = 12; ry--; }
    }

    const values = targetMonthHistory.map((v) => v.value);
    const n = values.length;
    const mean = n > 0 ? values.reduce((a, b) => a + b, 0) / n : 0;
    const variance = n > 1 ? values.reduce((s, v) => s + Math.pow(v - mean, 2), 0) / (n - 1) : 0;
    const stdDev = Math.sqrt(variance);

    const insufficientHistory = monthsAvailable < 2;
    const seasonalWindows = {};
    seasonalWindows[targetMonth] = {
      windowMonths: windowMonths.map((m) => String(m).padStart(2, "0")),
      historicalYears,
      historicalData,
      targetMonthHistory,
      historicalContext,
      recentMonths,
      statistics: {
        mean: parseFloat(mean.toFixed(3)),
        stdDev: parseFloat(stdDev.toFixed(3)),
        confidenceInterval: {
          lower: parseFloat(Math.max(0, mean - stdDev).toFixed(3)),
          upper: parseFloat((mean + stdDev).toFixed(3)),
        },
        sampleSize: n,
      },
      windowStatistics: { mean: 0, stdDev: 0, sampleSize: 0 },
    };

    results.push({
      SKU: skuCode,
      Descrição: description,
      Formato: formato,
      backtestTarget: targetMonth,
      realValue,
      historyMonthsAvailable: monthsAvailable,
      insufficientHistory,
      monthsMissingForMin: Math.max(0, 2 - monthsAvailable),
      dataReferencia: targetMonth + "-01",
      seasonalWindows,
    });
  }
}

return { analysis: results, targetMonths, totalSkus, skuOffset, skuLimit };

// =============================================================================
// Heurística Determinística Sazonal — JS port (sem runner Python).
// Reescrito 1:1 do Python original. Roda inline no worker do n8n.
// =============================================================================

function _mean(vals) {
  return vals.length ? vals.reduce((a, b) => a + b, 0) / vals.length : 0;
}
function _popStd(vals) {
  if (vals.length < 2) return 0;
  const m = _mean(vals);
  return Math.sqrt(vals.reduce((s, v) => s + (v - m) ** 2, 0) / vals.length);
}
function _recencyWeights(n) {
  if (n <= 0) return [];
  if (n === 1) return [4.0];
  if (n === 2) return [2.0, 4.0];
  if (n === 3) return [2.0, 2.0, 4.0];
  return [1.0, ...Array(n - 2).fill(2.0), 4.0];
}
function _weightedMean(vals, weights) {
  const tw = weights.reduce((a, b) => a + b, 0);
  if (tw === 0) return _mean(vals);
  let s = 0;
  for (let i = 0; i < vals.length; i++) s += vals[i] * weights[i];
  return s / tw;
}
function _ols(xs, ys) {
  const n = xs.length;
  if (n < 2) return [_mean(ys), 0];
  const mx = _mean(xs), my = _mean(ys);
  let num = 0, den = 0;
  for (let i = 0; i < n; i++) {
    num += (xs[i] - mx) * (ys[i] - my);
    den += (xs[i] - mx) ** 2;
  }
  if (Math.abs(den) < 1e-12) return [my, 0];
  const b = num / den;
  return [my - b * mx, b];
}
function _judgeHeuristic(values, trendBlend) {
  if (trendBlend == null) trendBlend = 0.7;
  const n = values.length;
  if (n === 0) return 0;
  if (n === 1) return values[0];
  const wAvg = _weightedMean(values, _recencyWeights(n));
  const ratios = [];
  for (let i = 0; i < n - 1; i++) if (values[i] > 0) ratios.push(values[i + 1] / values[i]);
  let trendRatio;
  if (ratios.length >= 2) trendRatio = 0.3 * ratios[0] + 0.7 * ratios[ratios.length - 1];
  else if (ratios.length) trendRatio = ratios[0];
  else trendRatio = 1.0;
  const trendForecast = Math.max(0, values[n - 1] * trendRatio);
  const histMean = _mean(values);
  const cv = histMean > 0 ? _popStd(values) / histMean : 0;
  const cvFactor = Math.min(cv, 1.0);
  let adaptive = trendBlend * (1.0 - cvFactor * 0.6);
  if (histMean > 0 && values[n - 1] / histMean < 0.3) adaptive *= 0.3;
  const anchor = cvFactor * histMean + (1.0 - cvFactor) * wAvg;
  return Math.max(0, adaptive * trendForecast + (1.0 - adaptive) * anchor);
}
function _judgeSes(values) {
  const n = values.length;
  if (n === 0) return 0;
  if (n === 1) return values[0];
  let bestError = Infinity, bestLevel = values[n - 1];
  for (let aX10 = 1; aX10 < 10; aX10++) {
    const alpha = aX10 / 10.0;
    let level = values[0], error = 0;
    for (let i = 1; i < n; i++) {
      error += (values[i] - level) ** 2;
      level = alpha * values[i] + (1 - alpha) * level;
    }
    if (error < bestError) { bestError = error; bestLevel = level; }
  }
  return Math.max(0, bestLevel);
}
function _judgeWindowTrend(values, years, histData) {
  const n = values.length;
  if (n === 0) return 0;
  if (n === 1) return values[0];
  const windowMeans = [], validYears = [];
  for (const yr of years) {
    const yk = String(yr);
    if (histData[yk]) {
      const wv = Object.values(histData[yk]);
      if (wv.length) { windowMeans.push(_mean(wv)); validYears.push(yr); }
    }
  }
  if (windowMeans.length < 2) return Math.max(0, _weightedMean(values, _recencyWeights(n)));
  const forecastYear = Math.max(...years) + 1;
  const [a, b] = _ols(validYears, windowMeans);
  const predictedWindowMean = a + b * forecastYear;
  const seasonalRatios = [];
  for (let i = 0; i < years.length; i++) {
    const yk = String(years[i]);
    if (histData[yk]) {
      const wv = Object.values(histData[yk]);
      const wm = _mean(wv);
      if (wm > 0) seasonalRatios.push(values[i] / wm);
    }
  }
  const seasonalRatio = seasonalRatios.length
    ? _weightedMean(seasonalRatios, _recencyWeights(seasonalRatios.length))
    : 1.0;
  const result = predictedWindowMean * seasonalRatio;
  if (result <= 0) return Math.max(0, _weightedMean(values, _recencyWeights(n)));
  return Math.max(0, result);
}
function _backtestWeights(values, years, histData) {
  const n = values.length;
  if (n < 3) return [1 / 3, 1 / 3, 1 / 3];
  const trainVals = values.slice(0, -1);
  const trainYears = years.slice(0, -1);
  const actual = values[n - 1];
  const lastYearKey = String(years[n - 1]);
  const trainHist = {};
  for (const k of Object.keys(histData)) if (k !== lastYearKey) trainHist[k] = histData[k];
  const preds = [
    _judgeHeuristic(trainVals),
    _judgeSes(trainVals),
    _judgeWindowTrend(trainVals, trainYears, trainHist),
  ];
  const errors = preds.map((p) => Math.abs(actual - p));
  const epsilon = Math.max(1.0, actual * 0.05);
  const invErrors = errors.map((e) => 1.0 / (e + epsilon));
  const total = invErrors.reduce((a, b) => a + b, 0);
  return invErrors.map((w) => w / total);
}
function _forecastTarget(values, years, histData) {
  const ph = _judgeHeuristic(values);
  const ps = _judgeSes(values);
  const pt = _judgeWindowTrend(values, years, histData);
  const w = _backtestWeights(values, years, histData);
  const prediction = ph * w[0] + ps * w[1] + pt * w[2];
  return {
    previsao: Math.max(0, parseFloat(prediction.toFixed(3))),
    metodos: {
      heuristica: parseFloat(ph.toFixed(3)),
      suavizacaoExponencial: parseFloat(ps.toFixed(3)),
      tendenciaSazonal: parseFloat(pt.toFixed(3)),
    },
    pesos: {
      heuristica: parseFloat(w[0].toFixed(3)),
      suavizacaoExponencial: parseFloat(w[1].toFixed(3)),
      tendenciaSazonal: parseFloat(w[2].toFixed(3)),
    },
  };
}
function _confidenceLabel(sampleSize, cvFactor) {
  if (sampleSize < 3) return 'baixa';
  if (cvFactor > 0.5) return 'média';
  return 'alta';
}
function _tolerancePct(values, prediction) {
  if (!values.length || prediction <= 0) return 30.0;
  const m = _mean(values);
  if (m <= 0) return 30.0;
  const cv = _popStd(values) / m;
  let pct = parseFloat((cv * 100).toFixed(1));
  if (pct < 10.0) pct = 10.0;
  if (pct > 60.0) pct = 60.0;
  return pct;
}
function _movingAverage3(window) {
  const recent = window.recentMonths || [];
  if (!recent.length) {
    const tmh = window.targetMonthHistory || [];
    return _mean(tmh.map((e) => e.value));
  }
  return _mean(recent.slice(0, 3).map((r) => r.value));
}
function seasonalForecast(skuData) {
  const formato = (skuData.Formato || '').trim();
  const formatoNorm = formato.toLowerCase();
  const base = {
    SKU: skuData.SKU,
    'Descrição': skuData['Descrição'] || '',
    Formato: formato,
    dataReferencia: skuData.dataReferencia || '',
    historyMonthsAvailable: skuData.historyMonthsAvailable || 0,
    insufficientHistory: !!skuData.insufficientHistory,
    monthsMissingForMin: skuData.monthsMissingForMin || 0,
  };
  const windows = skuData.seasonalWindows || {};
  if (base.insufficientHistory) {
    const previsoes = [];
    for (const tm of Object.keys(windows).sort()) {
      previsoes.push({
        mes: tm, previsao: 0, tolerancePct: 0,
        intervaloConfianca: { lower: 0, upper: 0 },
        confianca: 'baixa', motivo: 'historico_insuficiente',
        tipo: 'ensemble',
      });
    }
    base.previsoes = previsoes;
    return base;
  }
  const previsoes = [];
  const isComprados = formatoNorm === 'comprados';
  const isSgb = formatoNorm === 'sgb';
  for (const tm of Object.keys(windows).sort()) {
    const w = windows[tm];
    const targetHistory = w.targetMonthHistory || [];
    const stats = w.statistics || {};
    const histData = w.historicalData || {};
    const values = targetHistory.map((e) => e.value);
    const years = targetHistory.map((e) => e.year);
    const histMean = values.length ? _mean(values) : 0;
    const cv = histMean > 0 ? _popStd(values) / histMean : 0;
    const cvFactor = Math.min(cv, 1.0);
    if (isComprados) {
      const previsao = parseFloat(Math.max(0, _movingAverage3(w)).toFixed(3));
      const recentVals = (w.recentMonths || []).slice(0, 3).map((r) => r.value);
      const tol = _tolerancePct(recentVals, previsao);
      previsoes.push({
        mes: tm, previsao, tolerancePct: tol,
        intervaloConfianca: {
          lower: parseFloat(Math.max(0, previsao * (1 - tol / 100)).toFixed(3)),
          upper: parseFloat((previsao * (1 + tol / 100)).toFixed(3)),
        },
        confianca: _confidenceLabel(recentVals.length, cvFactor),
        tipo: 'comprados_sma3',
        metodos: { mediaMovel3: previsao },
        pesos: { mediaMovel3: 1.0 },
      });
      continue;
    }
    if (!values.length) {
      previsoes.push({
        mes: tm, previsao: 0, tolerancePct: 0,
        intervaloConfianca: { lower: 0, upper: 0 },
        confianca: 'baixa',
        tipo: isSgb ? 'sgb' : 'ensemble',
        motivo: 'sem_historico_no_mes_alvo',
      });
      continue;
    }
    const fc = _forecastTarget(values, years, histData);
    const tol = _tolerancePct(values, fc.previsao);
    // === v2 — Calibração por SKU (assimétrica leve, anti-sobra) ===
    // Grid-search 2D em (wRecent, biasFactor) usando histórico do próprio SKU.
    //
    // Penalidade ASSIMÉTRICA LEVE: sobrar custa 1.25× o de faltar.
    // (1.6× foi excessivo: 62% dos SKUs acabaram com viés ⬇ e v2 piorou em
    // mais SKUs do que melhorou.)
    //
    // - wRecent: peso da média recente (0..1, passo 0.05).
    // - biasFactor: viés multiplicativo final, GRID SIMÉTRICO em torno de 1.
    //   Usado SOMENTE quando há ≥3 amostras de histórico (evita overfit).
    //   Com 2 amostras: bias forçado em 1.00.
    //
    // Soft-cap final: SKUs com sobreprevisão crônica (≥75%) onde a previsão
    // ainda fica >40% acima do nível recente são capados em 1.25× recente.
    const _recentVals = (w.recentMonths || []).slice(0, 3).map((r) => r.value);
    const _recentLevel = _recentVals.length ? _mean(_recentVals) : null;
    const _histCtx = w.historicalContext || [];
    const _wGrid = [];
    for (let i = 0; i <= 20; i++) _wGrid.push(parseFloat((i / 20).toFixed(2))); // 0..1 step 0.05
    // bias só ativado com histórico suficiente (≥3 amostras)
    const _bGrid = _histCtx.length >= 3
      ? [0.92, 0.96, 1.00, 1.04, 1.08]   // simétrico
      : [1.00];
    const _UNDER_PENALTY = 1.0;   // faltar (tolerável)
    const _OVER_PENALTY = 1.25;   // sobrar (um pouco pior, mas sem exagero)
    let _wBest = null, _bBest = null, _wBestErr = null;
    let _overshootRate = 0;
    if (_histCtx.length >= 2) {
      // Diagnóstico: % de vezes que forecastStat sobrou vs actual.
      const overs = _histCtx.filter((c) => c.forecastStat > c.actual).length;
      _overshootRate = overs / _histCtx.length;
      let bestErr = Infinity;
      for (const wc of _wGrid) {
        for (const bc of _bGrid) {
          let sumErr = 0;
          for (const ctx of _histCtx) {
            const recMean = ctx.recent.length
              ? ctx.recent.reduce((a, b) => a + b, 0) / ctx.recent.length
              : ctx.forecastStat;
            const blend = (1 - wc) * ctx.forecastStat + wc * recMean;
            const pred = blend * bc;
            const diff = ctx.actual - pred;
            if (diff > 0) sumErr += diff * _UNDER_PENALTY;   // faltou
            else sumErr += (-diff) * _OVER_PENALTY;          // sobrou
